const express = require('express');
const fs = require('fs');
const path = require('path');

class APIGateway {
  constructor(config) {
    this.app = express();
    this.config = config;
    this.plugins = [];
    this.middlewareStack = [];
    this.setupMiddleware();
    this.loadPlugins();
  }

  setupMiddleware() {
    this.app.use(express.json());
    this.app.use(express.urlencoded({ extended: true }));
  }

  loadPlugins() {
    const pluginConfigs = this.config.plugins || [];
    
    pluginConfigs.forEach(pluginConfig => {
      try {
        let pluginCode;
        
        if (pluginConfig.code) {
          pluginCode = pluginConfig.code;
        } else if (pluginConfig.file) {
          const pluginPath = path.resolve(process.cwd(), pluginConfig.file);
          pluginCode = fs.readFileSync(pluginPath, 'utf8');
        } else if (pluginConfig.env) {
          pluginCode = process.env[pluginConfig.env];
        }
        
        if (pluginCode) {
          const plugin = this.createPlugin(pluginCode, pluginConfig.name);
          if (plugin) {
            this.plugins.push(plugin);
            this.applyPlugin(plugin);
          }
        }
      } catch (error) {
        console.error(`Failed to load plugin ${pluginConfig.name}:`, error.message);
      }
    });
  }

  createPlugin(code, name) {
    try {
      // Create a secure sandboxed environment
      const sandbox = {
        console,
        require: (module) => {
          // Whitelist allowed modules
          const allowedModules = ['fs', 'path', 'http', 'https', 'url'];
          if (allowedModules.includes(module)) {
            return require(module);
          }
          throw new Error(`Module ${module} not allowed`);
        },
        setTimeout,
        clearTimeout,
        setInterval,
        clearInterval,
        Buffer,
        Date,
        Math,
        JSON,
        String,
        Number,
        Array,
        Object,
        Function,
        Error,
        RegExp,
        Promise,
        process: {
          env: process.env,
          cwd: process.cwd
        }
      };

      // Use Function constructor instead of eval for better security
      const pluginFunction = new Function('sandbox', `
        const module = { exports: {} };
        const exports = module.exports;
        ${code}
        return module.exports;
      `);

      const plugin = pluginFunction(sandbox);
      plugin.name = name;
      return plugin;
    } catch (error) {
      console.error(`Failed to create plugin ${name}:`, error.message);
      return null;
    }
  }

  applyPlugin(plugin) {
    if (plugin.requestHandler) {
      this.middlewareStack.push({
        type: 'request',
        handler: plugin.requestHandler
      });
    }
    
    if (plugin.responseHandler) {
      this.middlewareStack.push({
        type: 'response',
        handler: plugin.responseHandler
      });
    }
    
    if (plugin.customLogic) {
      this.middlewareStack.push({
        type: 'logic',
        handler: plugin.customLogic
      });
    }
  }

  async executeMiddlewareStack(req, res, next) {
    try {
      let currentReq = req;
      let currentRes = res;
      
      for (const middleware of this.middlewareStack) {
        if (middleware.type === 'request' && currentReq) {
          currentReq = await middleware.handler(currentReq, currentRes);
        } else if (middleware.type === 'response' && currentRes) {
          currentRes = await middleware.handler(currentReq, currentRes);
        } else if (middleware.type === 'logic') {
          await middleware.handler(currentReq, currentRes);
        }
      }
      
      next();
    } catch (error) {
      console.error('Middleware execution error:', error);
      res.status(500).json({ error: 'Internal server error' });
    }
  }

  addRoute(method, route, handler) {
    const routeHandler = async (req, res, next) => {
      try {
        // Execute middleware stack
        await this.executeMiddlewareStack(req, res, next);
        
        // Execute original handler
        const result = await handler(req, res);
        if (result !== undefined) {
          res.json(result);
        }
      } catch (error) {
        console.error('Route handler error:', error);
        res.status(500).json({ error: 'Internal server error' });
      }
    };
    
    this.app[method.toLowerCase()](route, routeHandler);
  }

  start(port = 3000) {
    const server = this.app.listen(port, () => {
      console.log(`API Gateway listening on port ${port}`);
    });
    
    return server;
  }
}

// Plugin validation and security functions
function validatePluginCode(code) {
  // Check for dangerous patterns
  const dangerousPatterns = [
    /require\s*\(\s*["']child_process["']/,
    /require\s*\(\s*["']exec["']/,
    /eval\s*\(/,
    /Function\s*\(/,
    /process\s*\.\s*exit/,
    /process\s*\.\s*kill/,
    /__proto__/,
    /constructor/,
    /prototype/,
    /global/,
    /this/,
    /window/,
    /document/
  ];
  
  for (const pattern of dangerousPatterns) {
    if (pattern.test(code)) {
      throw new Error('Plugin contains dangerous code patterns');
    }
  }
  
  // Limit code size
  if (code.length > 10000) {
    throw new Error('Plugin code too large');
  }
  
  return true;
}

// Secure plugin loader
function loadSecurePlugin(pluginConfig) {
  try {
    let pluginCode;
    
    if (pluginConfig.code) {
      pluginCode = pluginConfig.code;
    } else if (pluginConfig.file) {
      const pluginPath = path.resolve(process.cwd(), pluginConfig.file);
      pluginCode = fs.readFileSync(pluginPath, 'utf8');
    } else if (pluginConfig.env) {
      pluginCode = process.env[pluginConfig.env];
    }
    
    if (pluginCode) {
      validatePluginCode(pluginCode);
      return pluginCode;
    }
  } catch (error) {
    console.error('Plugin loading error:', error.message);
  }
  
  return null;
}

module.exports = { APIGateway, loadSecurePlugin };